namespace Standard;/// <summary>/// 提供对本地原生 Win32 API 的安全调用包装类./// </summary>[SuppressUnmanagedCodeSecurity]internal static class SafeNativeMethods{    /// <summary>    /// 获取系统定义的鼠标双击时间间隔.    /// </summary>    /// <returns>返回双击的时间间隔，以毫秒为单位. </returns>    [DllImport("user32.dll", CharSet = CharSet.Auto, ExactSpelling = true)]    public static extern int GetDoubleClickTime();}